/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * <Replace with your name(s) and NetID(s).>
 */

#include <assert.h>
#include <pthread.h>

#include "csapp.h"

/* Thread pool buffer for concurrent request handling */
typedef struct {
	int *buf;		/* Buffer of connected descriptors */
	int n;			/* Maximum number of slots */
	int front;		/* Index of first item */
	int rear;		/* Index of next free item */
	sem_t mutex;		/* Protects accesses to buf */
	sem_t slots;		/* Counts available slots */
	sem_t items;		/* Counts available items */
} sbuf_t;

static void	client_error(int fd, const char *cause, int err_num,
		    const char *short_msg, const char *long_msg);
static char    *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int	parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);

/* Forward declarations */
static void doit(int fd, struct sockaddr_in *clientaddr);
static void *thread_routine(void *vargp);
static void sbuf_init(sbuf_t *sp, int n);
static void sbuf_deinit(sbuf_t *sp);
static void sbuf_insert(sbuf_t *sp, int item);
static int sbuf_remove(sbuf_t *sp);

/* Global variables */
static FILE *logfile;		/* Log file */
static pthread_mutex_t log_mutex;	/* Mutex for log file access */
static sbuf_t sbuf;		/* Shared buffer for thread pool */

/*
 * Requires:
 *   argc == 2 and argv[1] is a valid port number
 *
 * Effects:
 *   Starts a web proxy server listening on the given port.
 *   Uses a prethreaded pool approach to handle concurrent clients.
 */
int
main(int argc, char **argv)
{
	int listenfd, connfd;
	socklen_t clientlen;
	struct sockaddr_in clientaddr;
	int port;
	int i;
	pthread_t tid;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	port = atoi(argv[1]);

	/* Ignore SIGPIPE to prevent crash when writing to closed connection */
	Signal(SIGPIPE, SIG_IGN);

	/* Open log file */
	logfile = Fopen("proxy.log", "a");
	pthread_mutex_init(&log_mutex, NULL);

	/* Create listening socket */
	listenfd = Open_listenfd(port);

	/* Initialize the shared buffer */
	sbuf_init(&sbuf, MAXFD);

	/* Create pool threads */
	for (i = 0; i < 4; i++) {
		Pthread_create(&tid, NULL, thread_routine, NULL);
	}

	/* Main server loop */
	clientlen = sizeof(clientaddr);
	while (1) {
		connfd = Accept(listenfd, (SA *)&clientaddr, &clientlen);
		sbuf_insert(&sbuf, connfd);
	}

	/* Return success. */
	return (0);
}

