/*
 * Requires:
 *   sp is a pointer to a buffer with n slots, and n is positive.
 *
 * Effects:
 *   Initializes the buffer sp with n slots.
 */
static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf = Malloc(n * sizeof(int));
	sp->n = n;
	sp->front = sp->rear = 0;
	Sem_init(&sp->mutex, 0, 1);
	Sem_init(&sp->slots, 0, n);
	Sem_init(&sp->items, 0, 0);
}

/*
 * Requires:
 *   sp is a pointer to a buffer that was initialized with sbuf_init.
 *
 * Effects:
 *   Deinitializes the buffer sp.
 */
static void
sbuf_deinit(sbuf_t *sp)
{
	Free(sp->buf);
}

/*
 * Requires:
 *   sp is a pointer to a buffer initialized with sbuf_init.
 *
 * Effects:
 *   Inserts item onto the rear of the buffer sp.
 */
static void
sbuf_insert(sbuf_t *sp, int item)
{
	P(&sp->slots);				/* Wait for available slot */
	P(&sp->mutex);				/* Lock the buffer */
	sp->buf[(++sp->rear) % (sp->n)] = item;
	V(&sp->mutex);				/* Unlock the buffer */
	V(&sp->items);				/* Announce available item */
}

/*
 * Requires:
 *   sp is a pointer to a buffer initialized with sbuf_init.
 *
 * Effects:
 *   Removes and returns the first item from buffer sp.
 */
static int
sbuf_remove(sbuf_t *sp)
{
	int item;

	P(&sp->items);				/* Wait for available item */
	P(&sp->mutex);				/* Lock the buffer */
	item = sp->buf[(++sp->front) % (sp->n)];
	V(&sp->mutex);				/* Unlock the buffer */
	V(&sp->slots);				/* Announce available slot */
	return (item);
}

/*
 * Requires:
 *   vargp is NULL.
 *
 * Effects:
 *   Thread routine that handles client connections from the buffer.
 */
static void *
thread_routine(void *vargp)
{
	int connfd;
	struct sockaddr_in clientaddr;
	int clientlen;

	Pthread_detach(pthread_self());

	while (1) {
		connfd = sbuf_remove(&sbuf);
		clientlen = sizeof(clientaddr);

		/* Get client address from socket option */
		if (getpeername(connfd, (SA *)&clientaddr,
		    (socklen_t *)&clientlen) == 0) {
			doit(connfd, &clientaddr);
		}
		Close(connfd);
	}

	return (NULL);
}

/*
 * Requires:
 *   fd is an open socket connected to the client,
 *   clientaddr points to the client's socket address.
 *
 * Effects:
 *   Handles a single HTTP client request:
 *   - Reads the HTTP request from the client
 *   - Parses the URI
 *   - Connects to the server
 *   - Forwards the request
 *   - Receives and forwards the response
 *   - Logs the transaction
 */
static void
doit(int fd, struct sockaddr_in *clientaddr)
{
	char buf[MAXBUF], method[MAXLINE], uri[MAXLINE], version[MAXLINE];
	char hostname[MAXLINE], port[MAXLINE], pathname[MAXLINE];
	char *hostnamep, *portp, *pathnamep;
	rio_t rio_client, rio_server;
	int server_fd;
	int n;
	int response_size = 0;
	char line[MAXLINE];
	char request[MAXBUF];
	ssize_t nread;

	/* Read the request from client */
	Rio_readinitb(&rio_client, fd);

	/* Read the first line of the request */
	if ((nread = Rio_readlineb(&rio_client, buf, MAXBUF)) <= 0) {
		return;
	}

	/* Parse the request line */
	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
		client_error(fd, "Malformed request", 400, "Bad Request",
		    "Request line is malformed");
		return;
	}

	/* Only support GET */
	if (strcasecmp(method, "GET") != 0) {
		client_error(fd, "Method not supported", 501,
		    "Not Implemented",
		    "Proxy does not support this method");
		return;
	}

	/* Parse the URI */
	hostnamep = hostname;
	portp = port;
	pathnamep = pathname;

	if (parse_uri(uri, &hostnamep, &portp, &pathnamep) < 0) {
		client_error(fd, "Invalid URI", 400, "Bad Request",
		    "URI is invalid or not HTTP");
		Free(hostnamep);
		Free(portp);
		Free(pathnamep);
		return;
	}

	/* Connect to the server */
	server_fd = Open_clientfd(hostnamep, portp);
	if (server_fd < 0) {
		client_error(fd, "Unable to connect to server", 502,
		    "Bad Gateway",
		    "Failed to connect to origin server");
		Free(hostnamep);
		Free(portp);
		Free(pathnamep);
		return;
	}

	/* Initialize RIO for server */
	Rio_readinitb(&rio_server, server_fd);

	/* Build request to send to server (with path only, not full URI) */
	snprintf(request, MAXBUF, "GET %s HTTP/1.0\r\n", pathnamep);

	/* Read and forward headers from client to server, modifying as needed */
	while (1) {
		if ((nread = Rio_readlineb(&rio_client, line, MAXLINE)) <= 0) {
			break;
		}

		/* Skip connection-related headers */
		if ((strncasecmp(line, "Connection:", 11) == 0) ||
		    (strncasecmp(line, "Keep-Alive:", 11) == 0) ||
		    (strncasecmp(line, "Proxy-Connection:", 16) == 0)) {
			continue;
		}

		/* Stop at empty line (end of headers) */
		if (strcmp(line, "\r\n") == 0) {
			break;
		}

		/* Forward the header to server */
		strncat(request, line, MAXBUF - strlen(request) - 1);
	}

	/* Add Connection: close header */
	strncat(request, "Connection: close\r\n", MAXBUF - strlen(request) - 1);

	/* Add final CRLF to complete headers */
	strncat(request, "\r\n", MAXBUF - strlen(request) - 1);

	/* Send the request to the server */
	Rio_writen(server_fd, request, strlen(request));

	/* Read response from server and forward to client */
	while ((nread = Rio_readnb(&rio_server, buf, MAXBUF)) > 0) {
		Rio_writen(fd, buf, nread);
		response_size += nread;
	}

	/* Log the transaction */
	char *log_entry = create_log_entry(clientaddr, uri, response_size);
	pthread_mutex_lock(&log_mutex);
	fprintf(logfile, "%s\n", log_entry);
	fflush(logfile);
	pthread_mutex_unlock(&log_mutex);
	Free(log_entry);

	/* Clean up */
	Close(server_fd);
	Free(hostnamep);
	Free(portp);
	Free(pathnamep);
}

